 1	import * as React from 'react';
 2	import { IstioLevelToSeverity, ObjectCheck, ValidationMessage, ValidationTypes } from '../../../types/IstioObjects';
 3	import { Flex, FlexItem, Stack, StackItem, Title, TitleSizes, Tooltip, TooltipPosition } from '@patternfly/react-core';
 4	import { Validation } from '../../../components/Validations/Validation';
 5	import { KialiIcon } from '../../../config/KialiIcon';
 6	import { kialiStyle } from 'styles/StyleUtils';
 7	
 8	interface Props {
 9	  messages?: ValidationMessage[];
10	  checks?: ObjectCheck[];
11	}
12	
13	const statusInfoStyle = kialiStyle({
14	  verticalAlign: '-0.125em !important'
15	});
16	
17	export class IstioStatusMessageList extends React.Component<Props> {
18	  render() {
19	    return (
20	      <>
21	        <Stack>
22	          <StackItem>
23	            <Title headingLevel="h4" size={TitleSizes.lg} style={{ paddingBottom: '10px' }}>
24	              Configuration Analysis
25	            </Title>
26	          </StackItem>
27	          {(this.props.messages || []).map((msg: ValidationMessage, i: number) => {
28	            const severity: ValidationTypes = IstioLevelToSeverity[msg.level || 'UNKNOWN'];
29	            return (
30	              <StackItem id={'msg-' + i}>
31	                <Flex>
32	                  <FlexItem>
33	                    <Validation severity={severity} />
34	                  </FlexItem>
35	                  <FlexItem>
36	                    <a href={msg.documentationUrl} target="_blank" rel="noopener noreferrer">
37	                      {msg.type.code}
38	                    </a>
39	                    {msg.description ? ': ' + msg.description : undefined}
40	                  </FlexItem>
41	                </Flex>
42	              </StackItem>
43	            );
44	          })}
45	          <Stack>
46	            {(this.props.checks || []).map((check, index) => {
47	              const severity: ValidationTypes = IstioLevelToSeverity[check.severity.toUpperCase() || 'UNKNOWN'];
48	              return (
49	                <StackItem id={'valid_msg-' + index}>
50	                  <Flex>
51	                    <FlexItem>
52	                      <Validation severity={severity} />
53	                    </FlexItem>
54	                    <FlexItem>{check.code}</FlexItem>
55	                    <Tooltip content={check.message} position={TooltipPosition.right}>
56	                      <div className="iconInfo">
57	                        <KialiIcon.Info className={statusInfoStyle} />
58	                      </div>
59	                    </Tooltip>
60	                  </Flex>
61	                </StackItem>
62	              );
63	            })}
64	          </Stack>
65	        </Stack>
66	      </>
67	    );
68	  }
69	}

